from __future__ import annotations

from datetime import datetime
from typing import Dict, List

from dq.registry import CheckResult
from dq.severity import ERROR, WARN


def not_null_check(records: List[Dict[str, object]], column: str, severity: str = ERROR) -> CheckResult:
    """Fail when any record has a null/missing value for the column."""
    # BUG: always passes.
    return CheckResult(check=f"not_null:{column}", passed=True, severity=severity, failing=[])


def unique_check(records: List[Dict[str, object]], column: str, severity: str = ERROR) -> CheckResult:
    """Fail when the column has duplicate values."""
    # BUG: always passes.
    return CheckResult(check=f"unique:{column}", passed=True, severity=severity, failing=[])


def accepted_values_check(records: List[Dict[str, object]], column: str, allowed: List, severity: str = ERROR) -> CheckResult:
    """Fail when the column holds a value outside the allowed set."""
    # BUG: always passes.
    return CheckResult(check=f"accepted_values:{column}", passed=True, severity=severity, failing=[])


def freshness_check(records: List[Dict[str, object]], column: str, max_age_days: int, now: datetime, severity: str = WARN) -> CheckResult:
    """Fail when any ISO-date value in the column is older than max_age_days."""
    # BUG: always passes.
    return CheckResult(check=f"freshness:{column}", passed=True, severity=severity, failing=[])
